<script>
(function(){
  "use strict";

  const canvas=document.getElementById("coin-hero");
  const ctx=canvas.getContext("2d");
  const W=canvas.width,H=canvas.height;
  const R=214, THICK=25, SCALE=1;
  let running=true, raf=0, start=performance.now();

  function makeFace(kind){
    const S=640,c=document.createElement("canvas");
    c.width=c.height=S;
    const g=c.getContext("2d"),m=S/2,r=302;

    g.save();
    g.beginPath();g.arc(m,m,r,0,Math.PI*2);g.clip();

    let base=g.createRadialGradient(m-115,m-145,18,m,m,r*1.25);
    base.addColorStop(0,"#fff0bd");
    base.addColorStop(.18,"#d9a95e");
    base.addColorStop(.48,"#8a5428");
    base.addColorStop(.73,"#d39b4e");
    base.addColorStop(1,"#4b2918");
    g.fillStyle=base;g.fillRect(0,0,S,S);

    const sweep=g.createLinearGradient(40,580,590,20);
    sweep.addColorStop(0,"rgba(20,7,0,.42)");
    sweep.addColorStop(.38,"rgba(255,230,161,.18)");
    sweep.addColorStop(.5,"rgba(255,255,232,.48)");
    sweep.addColorStop(.62,"rgba(91,45,16,.12)");
    sweep.addColorStop(1,"rgba(23,10,3,.4)");
    g.fillStyle=sweep;g.fillRect(0,0,S,S);

    for(let i=0;i<1100;i++){
      const a=i*2.399963, rr=Math.sqrt((i+.5)/1100)*r;
      const x=m+Math.cos(a)*rr,y=m+Math.sin(a)*rr;
      g.fillStyle=i%3?"rgba(255,240,190,.025)":"rgba(42,18,4,.045)";
      g.fillRect(x,y,1.3,1.3);
    }
    g.restore();

    function ring(rad,width,light,dark){
      g.beginPath();g.arc(m,m,rad,0,Math.PI*2);
      g.lineWidth=width;g.strokeStyle=dark;g.stroke();
      g.beginPath();g.arc(m-1.5,m-2,rad,0,Math.PI*2);
      g.lineWidth=Math.max(1,width*.38);g.strokeStyle=light;g.stroke();
    }
    ring(300,10,"rgba(255,235,171,.8)","rgba(45,20,8,.85)");
    ring(270,8,"rgba(255,224,151,.62)","rgba(65,29,10,.72)");
    ring(236,3,"rgba(255,227,160,.55)","rgba(54,23,8,.65)");

    g.textAlign="center";g.textBaseline="middle";
    if(kind==="front"){
      g.save();
      g.translate(m,m-8);
      g.shadowColor="rgba(45,18,4,.95)";g.shadowBlur=1;g.shadowOffsetX=7;g.shadowOffsetY=8;
      g.fillStyle="#c88b43";
      g.beginPath();
      for(let i=0;i<8;i++){
        const a=-Math.PI/2+i*Math.PI/4,rad=i%2?114:137;
        const x=Math.cos(a)*rad,y=Math.sin(a)*rad;
        i?g.lineTo(x,y):g.moveTo(x,y);
      }
      g.closePath();g.fill();
      g.shadowOffsetX=-4;g.shadowOffsetY=-5;g.shadowColor="rgba(255,231,162,.7)";
      g.lineWidth=16;g.strokeStyle="#bd7c37";g.stroke();
      g.shadowColor="rgba(42,17,4,.9)";g.shadowOffsetX=6;g.shadowOffsetY=7;
      g.fillStyle="#e4b766";g.font="900 142px Arial";
      g.fillText("WT",0,5);
      g.restore();

      g.fillStyle="#4c2712";g.font="900 29px Arial";
      g.letterSpacing="4px";
      g.fillText("WASTEDTOKEN",m,85);
      g.font="700 18px Arial";g.fillText("PRIVATE MINT • ARTIFACT 001",m,552);
      for(let i=0;i<12;i++){
        const a=i*Math.PI/6;
        g.beginPath();g.arc(m+Math.cos(a)*254,m+Math.sin(a)*254,4,0,7);
        g.fillStyle="#5b2c12";g.fill();
      }
    }else{
      g.fillStyle="#5b2c12";g.font="900 30px Arial";g.fillText("PROOF OF POSSESSION",m,102);
      g.shadowColor="rgba(255,229,158,.7)";g.shadowOffsetX=-4;g.shadowOffsetY=-5;
      g.fillStyle="#a96d31";g.font="900 105px Arial";g.fillText("10,000",m,282);
      g.shadowColor="rgba(50,20,4,.9)";g.shadowOffsetX=5;g.shadowOffsetY=6;
      g.fillStyle="#d69c4e";g.font="900 57px Arial";g.fillText("TOKENS",m,372);
      g.shadowColor="transparent";g.fillStyle="#54290f";g.font="700 17px Arial";
      g.fillText("ONE HEAVY UNIT • ZERO DIGITAL UTILITY",m,520);
      for(let i=0;i<24;i++){
        let a=i*Math.PI/12;
        let x=m+Math.cos(a)*215,y=m+Math.sin(a)*215;
        g.beginPath();g.arc(x,y,6,0,7);g.fill();
      }
      g.lineWidth=3;g.strokeStyle="rgba(75,34,10,.65)";
      g.beginPath();g.moveTo(155,430);g.lineTo(215,430);g.lineTo(245,460);
      g.moveTo(485,430);g.lineTo(425,430);g.lineTo(395,460);g.stroke();
    }
    return c;
  }

  const front=makeFace("front"),back=makeFace("back");

  function orientation(t){
    const ay=Math.PI*2*t;
    const ax=Math.PI*4*t;
    const cy=Math.cos(ay),sy=Math.sin(ay),cx=Math.cos(ax),sx=Math.sin(ax);
    return {
      X:{x:cy,y:0,z:-sy},
      Y:{x:sy*sx,y:cx,z:cy*sx},
      Z:{x:sy*cx,y:-sx,z:cy*cx}
    };
  }
  function project(M,x,y,z){
    const px=M.X.x*x+M.Y.x*y+M.Z.x*z;
    const py=M.X.y*x+M.Y.y*y+M.Z.y*z;
    const pz=M.X.z*x+M.Y.z*y+M.Z.z*z;
    return {x:W/2+px*SCALE,y:H/2-py*SCALE,z:pz};
  }

  function render(t){
    t=Math.max(0,Math.min(1,Number(t)||0));
    ctx.setTransform(1,0,0,1,0,0);
    ctx.clearRect(0,0,W,H);

    let bg=ctx.createRadialGradient(W/2,H/2,30,W/2,H/2,370);
    bg.addColorStop(0,"#181613");
    bg.addColorStop(.55,"#0d0f10");
    bg.addColorStop(1,"#08090a");
    ctx.fillStyle=bg;ctx.fillRect(0,0,W,H);

    ctx.save();
    ctx.translate(W/2,H/2);
    ctx.strokeStyle="rgba(202,166,105,.05)";
    for(let r=245;r<360;r+=38){ctx.beginPath();ctx.arc(0,0,r,0,7);ctx.stroke()}
    ctx.restore();

    const M=orientation(t);
    const segs=128, quads=[];
    const light={x:-.38,y:.48,z:.79};
    for(let i=0;i<segs;i++){
      const a=i*Math.PI*2/segs,b=(i+1)*Math.PI*2/segs;
      const ca=Math.cos(a),sa=Math.sin(a),cb=Math.cos(b),sb=Math.sin(b);
      const p1=project(M,R*ca,R*sa,-THICK);
      const p2=project(M,R*cb,R*sb,-THICK);
      const p3=project(M,R*cb,R*sb,THICK);
      const p4=project(M,R*ca,R*sa,THICK);
      const mid=(a+b)/2,nx=Math.cos(mid),ny=Math.sin(mid);
      const wx=M.X.x*nx+M.Y.x*ny;
      const wy=M.X.y*nx+M.Y.y*ny;
      const wz=M.X.z*nx+M.Y.z*ny;
      let lum=Math.max(0,wx*light.x+wy*light.y+wz*light.z);
      const reed=i%2===0?1:-1;
      quads.push({p1,p2,p3,p4,z:(p1.z+p2.z+p3.z+p4.z)/4,lum,reed});
    }
    quads.sort((a,b)=>a.z-b.z);
    quads.forEach(q=>{
      const v=Math.round(53+q.lum*138+q.reed*12);
      ctx.beginPath();ctx.moveTo(q.p1.x,q.p1.y);ctx.lineTo(q.p2.x,q.p2.y);
      ctx.lineTo(q.p3.x,q.p3.y);ctx.lineTo(q.p4.x,q.p4.y);ctx.closePath();
      ctx.fillStyle=`rgb(${Math.min(220,v+35)},${Math.min(172,v)},${Math.max(25,v-45)})`;
      ctx.fill();
      ctx.strokeStyle=q.reed>0?"rgba(255,224,154,.32)":"rgba(35,13,3,.42)";
      ctx.lineWidth=1.1;ctx.stroke();
    });

    const isFront=M.Z.z>=0;
    const face=isFront?front:back;
    const zFace=isFront?THICK:-THICK;
    const center=project(M,0,0,zFace);
    const S=face.width, mul=2*R/S;
    let bxX=M.X.x*mul, bxY=-M.X.y*mul;
    if(!isFront){bxX=-bxX;bxY=-bxY}
    const byX=M.Y.x*mul,byY=-M.Y.y*mul;

    ctx.save();
    ctx.setTransform(bxX,bxY,byX,byY,center.x,center.y);
    ctx.drawImage(face,-S/2,-S/2);
    ctx.restore();

    ctx.save();
    ctx.beginPath();
    ctx.setTransform(M.X.x*R,-M.X.y*R,M.Y.x*R,-M.Y.y*R,center.x,center.y);
    ctx.arc(0,0,1,0,Math.PI*2);
    ctx.setTransform(1,0,0,1,0,0);
    ctx.clip();

    const sweepX=center.x + Math.sin(Math.PI*2*t+.45)*R*.7;
    let shine=ctx.createLinearGradient(sweepX-105,center.y+135,sweepX+105,center.y-135);
    shine.addColorStop(0,"rgba(255,255,230,0)");
    shine.addColorStop(.38,"rgba(255,239,180,.03)");
    shine.addColorStop(.5,"rgba(255,255,239,.48)");
    shine.addColorStop(.59,"rgba(255,220,145,.12)");
